export type EditorKnowledgeTranslationKey = (typeof editorKnowledgeEntries)[number][0];

export const editorKnowledgeMessages: Record<
  Locale,
  Record<EditorKnowledgeTranslationKey, string>
> = Object.fromEntries(
  supportedLocales.map((locale) => [
    locale,
    Object.fromEntries(
      editorKnowledgeEntries.map(([key, translations]) => [key, translations[locale]]),
    ),
  ]),
) as Record<Locale, Record<EditorKnowledgeTranslationKey, string>>;
